37	function seededRandom(seed: number): () => number {
38	  let s = seed;
39	  return () => {
40	    s = (s * 1664525 + 1013904223) & 0xffffffff;
41	    return (s >>> 0) / 0xffffffff;
42	  };
43	}
44	
45	export function generateTransactions(
46	  count: number,
47	  seed: number = 42
48	): Transaction[] {
49	  const random = seededRandom(seed);
50	  const transactions: Transaction[] = [];
51	  const userCount = Math.max(10, Math.floor(count / 100));
52	
53	  for (let i = 0; i < count; i++) {
54	    const userId = `user-${Math.floor(random() * userCount)}`;
55	    const category = CATEGORIES[Math.floor(random() * CATEGORIES.length)];
56	    const description =
57	      DESCRIPTIONS[Math.floor(random() * DESCRIPTIONS.length)];
58	    const amount = Math.round(random() * 50000) / 100;
59	    const dayOffset = Math.floor(random() * 365);
60	    const date = new Date(2025, 0, 1 + dayOffset).toISOString().split("T")[0];
61	
62	    transactions.push({
63	      id: `txn-${i}`,
64	      userId,
65	      amount,
66	      category,
67	      date,
68	      description,
69	    });
70	  }
71	
72	  return transactions;
73	}
74	
75	export function generateTransactionsWithDuplicates(
76	  count: number,
77	  duplicateCount: number,
78	  seed: number = 42
79	): Transaction[] {
80	  const transactions = generateTransactions(count, seed);
81	
82	  const random = seededRandom(seed + 999);
83	
84	  for (let i = 0; i < duplicateCount; i++) {
85	    const sourceIdx = Math.floor(random() * Math.min(count, transactions.length));
86	    const source = transactions[sourceIdx];
87	
88	    transactions.push({
89	      id: `txn-dup-${i}`,
90	      userId: source.userId,
91	      amount: source.amount,
92	      category: source.category,
93	      date: source.date,
94	      description: source.description + " (duplicate)",
95	    });
96	  }
97	
98	  return transactions;
99	}
