export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, { group: DuplicateGroup; seen: Set<string> }>();

  for (const transaction of transactions) {
    const key = `${transaction.userId}|${transaction.amount}|${transaction.date}`;
    const entry = map.get(key);
    if (entry) {
      if (!entry.seen.has(transaction.id)) {
        entry.seen.add(transaction.id);
        entry.group.transactions.push(transaction);
      }
    } else {
      map.set(key, {
        group: { key, transactions: [transaction] },
        seen: new Set([transaction.id]),
      });
    }
  }

  return Array.from(map.values())
    .filter((e) => e.group.transactions.length > 1)
    .map((e) => e.group);
}

